26	
27	namespace
28	{
29	
30	// Convert a number in the range -1.0 <= n <= 1.0 to 0.0 <= n < 1.0
31	// If the number is less than 0, add 1 so it wraps around
32	inline vecf16_t wrapfv(vecf16_t in)
33	{
34	    return __builtin_nyuzi_vector_mixf(__builtin_nyuzi_mask_cmpf_lt(in, vecf16_t(0.0)),
35	                                       in + vecf16_t(1.0), in);
36	}
37	
38	// If a number is greater than max, make it be zero.
39	// This wraps in the case that 0 <= in <= max.
40	inline veci16_t wrapiv(veci16_t in, int max)
41	{
42	    return __builtin_nyuzi_vector_mixi(__builtin_nyuzi_mask_cmpf_lt(in, veci16_t(max)),
43	                                       in, veci16_t(0));
44	}
45	
46	} // namespace
47	
48	Texture::Texture()
49	{
50	    for (int i = 0; i < kMaxMipLevels; i++)
51	        fMipSurfaces[i] = nullptr;
52	}
53	
54	void Texture::setMipSurface(int mipLevel, const Surface *surface)
55	{
56	    assert(mipLevel < kMaxMipLevels);
57	
58	    fMipSurfaces[mipLevel] = surface;
59	    if (mipLevel > fMaxMipLevel)
60	        fMaxMipLevel = mipLevel;
61	
62	    if (mipLevel == 0)
63	    {
64	        fBaseMipBits = __builtin_clz(static_cast<unsigned int>(surface->getWidth())) + 1;
65	
66	        // Clear out lower mip levels
67	        for (int i = 1; i < fMaxMipLevel; i++)
68	            fMipSurfaces[i] = 0;
69	
70	        fMaxMipLevel = 0;
71	    }
72	    else
73	    {
74	        assert(surface->getWidth() == fMipSurfaces[0]->getWidth() >> mipLevel);
75	    }
76	}
77	
78	void Texture::readPixels(vecf16_t u, vecf16_t v, vmask_t mask,
79	                         vecf16_t *outColor) const
80	{
81	    // Determine the closest mip-level. Compute the pitch between the top
82	    // two pixels. The reciprocal of this is the scaled texture size. log2 of this
83	    // is the mip level.
84	    // XXX this is a hack because it only looks at one direction. Should do
85	    // something better here.
86	    int mipLevel = __builtin_clz(static_cast<unsigned int>(1.0f /
87	                                 __builtin_fabsf(u[1] - u[0]))) - fBaseMipBits;
88	    if (mipLevel > fMaxMipLevel)
89	        mipLevel = fMaxMipLevel;
90	    else if (mipLevel < 0)
91	        mipLevel = 0;
92	
93	    const Surface *surface = fMipSurfaces[mipLevel];
94	    int mipWidth = surface->getWidth();
95	    int mipHeight = surface->getHeight();
96	
97	    // Convert from texture space (0.0-1.0, 1.0-0.0) to raster coordinates
98	    // (0-(width - 1), 0-(height - 1)). Note that the top of the texture corresponds
99	    // to v of 1.0. Coordinates wrap.
100	    vecf16_t uRaster = wrapfv(fracfv(u)) * (mipWidth - 1);
101	    vecf16_t vRaster = (1.0 - wrapfv(fracfv(v))) * (mipHeight - 1);
102	    veci16_t tx = __builtin_convertvector(uRaster, veci16_t);
103	    veci16_t ty = __builtin_convertvector(vRaster, veci16_t);
104	
105	    if (fEnableBilinearFiltering)
106	    {
107	        // Load four source texels that overlap the sample position
108	        vecf16_t tlColor[4];	// top left
109	        vecf16_t trColor[4];	// top right
110	        vecf16_t blColor[4];	// bottom left
111	        vecf16_t brColor[4];	// bottom right
112	
113	        // These wrap around the edge of the texture
114	        veci16_t xPlusOne = wrapiv(tx + 1, mipWidth);
115	        veci16_t yPlusOne = wrapiv(ty + 1, mipHeight);
116	
117	        surface->readPixels(tx, ty, mask, tlColor);
118	        surface->readPixels(tx, yPlusOne, mask, blColor);
119	        surface->readPixels(xPlusOne, ty, mask, trColor);
120	        surface->readPixels(xPlusOne, yPlusOne, mask, brColor);
121	
122	        // Compute weights
123	        vecf16_t wu = fracfv(uRaster);
124	        vecf16_t wv = fracfv(vRaster);
125	        vecf16_t tlWeight = (1.0 - wu) * (1.0 - wv);
126	        vecf16_t trWeight = wu * (1.0 - wv);
127	        vecf16_t blWeight = (1.0 - wu) * wv;
128	        vecf16_t brWeight = wu * wv;
129	
130	        // Apply weights & blend
131	        for (int channel = 0; channel < 4; channel++)
132	        {
133	            outColor[channel] = (tlColor[channel] * tlWeight)
134	                                + (blColor[channel] * blWeight)
135	                                + (trColor[channel] * trWeight)
136	                                + (brColor[channel] * brWeight);
137	        }
138	    }
139	    else
140	    {
141	        // Nearest neighbor
142	        surface->readPixels(tx, ty, mask, outColor);
143	    }
144	}
145	
146	} // namespace librender
