53	    uint32_t numVertices;
54	    uint32_t numIndices;
55	};
56	
57	const int kAttrsPerVertex = 8;
58	
59	char *readResourceFile()
60	{
61	    FileHeader header;
62	    char *resourceData;
63	    FILE *fp;
64	
65	    fp = fopen("resource.bin", "rb");
66	    if (fp == nullptr)
67	    {
68	        printf("can't find resource.bin\n");
69	        return nullptr;
70	    }
71	
72	    // Read the first block to determine how large the rest of the file is.
73	    if (fread(&header, sizeof(header), 1, fp) != 1)
74	    {
