84	    if (fread(resourceData, header.fileSize, 1, fp) != 1)
85	    {
86	        fclose(fp);
87	        free(resourceData);
88	        printf("error reading resource file\n");
89	        return nullptr;
90	    }
91	
92	    fclose(fp);
93	
94	    return resourceData;
95	}
96	
97	#if TEST_TEXTURE
98	
99	// Test texture
100	const int kTestTextureSize = 128;
101	const int kCheckerSize = 32;
102	
103	Texture *createCheckerboardTexture()
104	{
105	    const uint32_t kColors[] = {
106	        0x00ff0000,
107	        0x0000ff00,
108	        0x000000ff,
109	        0x00ff00ff,
110	    };
111	
112	    Texture *texture = new Texture;
113	    for (int mipLevel = 0; mipLevel < 4; mipLevel++)
114	    {
115	        int mipSize = kTestTextureSize >> mipLevel;
116	        int subCheckerSize = kCheckerSize >> mipLevel;
117	        uint32_t checkerColor = kColors[mipLevel];
118	        Surface *surface = new Surface(mipSize, mipSize, Surface::RGBA8888);
119	        uint32_t *bits = (uint32_t*) surface->bits();
120	        for (int x = 0; x < mipSize; x++)
121	        {
122	            for (int y = 0; y < mipSize; y++)
123	            {
124	                if (((x / subCheckerSize) & 1) ^ ((y / subCheckerSize) & 1))
125	                    bits[y * mipSize + x] = checkerColor;
126	                else
127	                    bits[y * mipSize + x] = 0xffffffff;
128	            }
129	        }
130	
131	        texture->setMipSurface(mipLevel, surface);
132	    }
133	
134	    return texture;
135	}
136	
137	#endif
138	
139	}
