142	int main()
143	{
144	    void *frameBuffer;
145	    if (get_current_thread_id() != 0)
146	        worker_thread();
147	
148	    // Set up render context
149	    frameBuffer = init_vga(VGA_MODE_640x480);
150	
151	    // Set up resource data
152	    char *resourceData = readResourceFile();
153	    const FileHeader *fileHeader = reinterpret_cast<const FileHeader*>(resourceData);
154	#ifndef TEST_TEXTURE
155	    const TextureEntry *texHeader = reinterpret_cast<const TextureEntry*>(resourceData
156	            + sizeof(FileHeader));
157	#endif
158	    const MeshEntry *meshHeader = reinterpret_cast<const MeshEntry*>(resourceData
159	            + sizeof(FileHeader) + fileHeader->numTextures * sizeof(TextureEntry));
160	    Texture **textures = new Texture*[fileHeader->numTextures];
161	
162	    printf("%u textures %u meshes\n", fileHeader->numTextures, fileHeader->numMeshes);
163	
164	    // Create texture objects
165	    for (unsigned int textureIndex = 0; textureIndex < fileHeader->numTextures; textureIndex++)
166	    {
167	#if TEST_TEXTURE
168	        textures[textureIndex] = createCheckerboardTexture();
169	#else
170	        textures[textureIndex] = new Texture();
171	        textures[textureIndex]->enableBilinearFiltering(true);
172	        int offset = texHeader[textureIndex].offset;
173	        for (unsigned int mipLevel = 0; mipLevel < texHeader[textureIndex].mipLevels; mipLevel++)
174	        {
175	            int width = texHeader[textureIndex].width >> mipLevel;
176	            int height = texHeader[textureIndex].height >> mipLevel;
177	            Surface *surface = new Surface(width, height, Surface::RGBA8888,
178	                resourceData + offset);
179	            textures[textureIndex]->setMipSurface(mipLevel, surface);
180	            offset += width * height * 4;
181	        }
182	#endif
183	    }
184	
185	    // Create Render Buffers
186	    RenderBuffer *vertexBuffers = new RenderBuffer[fileHeader->numMeshes];
187	    RenderBuffer *indexBuffers = new RenderBuffer[fileHeader->numMeshes];
188	    for (unsigned int meshIndex = 0; meshIndex < fileHeader->numMeshes; meshIndex++)
189	    {
190	        const MeshEntry &entry = meshHeader[meshIndex];
191	        vertexBuffers[meshIndex].setData(resourceData + entry.offset,
192	                                         entry.numVertices, sizeof(float) * kAttrsPerVertex);
193	        indexBuffers[meshIndex].setData(resourceData + entry.offset + entry.numVertices
194	                                        * kAttrsPerVertex * sizeof(float), entry.numIndices, sizeof(int));
195	    }
196	
197	    // Set up render state
198	    RenderContext *context = new RenderContext(0x1000000);
199	    RenderTarget *renderTarget = new RenderTarget();
200	    Surface *colorBuffer = new Surface(FB_WIDTH, FB_HEIGHT, Surface::RGBA8888, frameBuffer);
201	    Surface *depthBuffer = new Surface(FB_WIDTH, FB_HEIGHT, Surface::FLOAT);
202	    renderTarget->setColorBuffer(colorBuffer);
203	    renderTarget->setDepthBuffer(depthBuffer);
204	    context->bindTarget(renderTarget);
205	    context->enableDepthBuffer(true);
206	#if SHOW_DEPTH
207	    context->bindShader(new DepthShader());
208	#else
209	    context->bindShader(new TextureShader());
210	#endif
211	    context->setClearColor(0.52, 0.80, 0.98);
212	
213	    Matrix projectionMatrix = Matrix::getProjectionMatrix(FB_WIDTH, FB_HEIGHT);
214	
215	    TextureUniforms uniforms;
216	    uniforms.fLightDirection = Vec3(-1, -0.5, 1).normalized();
217	    uniforms.fDirectional = 0.5f;
218	    uniforms.fAmbient = 0.4f;
219	    float theta = 0.0;
220	
221	    start_all_threads();
222	
223	    for (int frame = 0; ; frame++)
224	    {
225	        Matrix modelViewMatrix = Matrix::lookAt(Vec3(cos(theta) * 6, 3, sin(theta) * 6), Vec3(0, 3.1, 0),
226	                                                Vec3(0, 1, 0));
227	        theta = theta + M_PI / 8;
228	        if (theta > M_PI * 2)
229	            theta -= M_PI * 2;
230	
231	        uniforms.fMVPMatrix = projectionMatrix * modelViewMatrix;
232	        uniforms.fNormalMatrix = modelViewMatrix.upper3x3();
233	
234	        context->clearColorBuffer();
235	        for (unsigned int meshIndex = 0; meshIndex < fileHeader->numMeshes; meshIndex++)
236	        {
237	            const MeshEntry &entry = meshHeader[meshIndex];
238	            if (entry.textureId != 0xffffffff)
239	            {
240	                assert(entry.textureId < fileHeader->numTextures);
241	                context->bindTexture(0, textures[entry.textureId]);
242	                uniforms.fHasTexture = true;
243	            }
244	            else
245	                uniforms.fHasTexture = false;
246	
247	            context->bindUniforms(&uniforms, sizeof(uniforms));
248	            context->bindVertexAttrs(&vertexBuffers[meshIndex]);
249	            context->drawElements(&indexBuffers[meshIndex]);
250	        }
251	
252	        clock_t startTime = clock();
253	        context->finish();
254	        printf("rendered frame in %d uS\n", clock() - startTime);
255	    }
256	
257	    delete[] textures;
258	
259	    return 0;
260	}
